//! Perfect-mimicry shadow: where misrouted callers land.
//!
//! Reuses moonshine's own Shadow Mode idea (a thermodynamic-trace fake-output
//! engine) but with one hard inversion. moonshine's `shadow` builtin actually
//! executes the real command and only dresses the output. That is unacceptable
//! for a decoy — an adversary's commands would run for real. The shadow here
//! NEVER executes; it fabricates a response shaped exactly like a real moonshine
//! result, with a latency drawn to match the real distribution.
//!
//! Decision (locked): perfect mimicry. The fabricated response must be
//! statistically indistinguishable from a real one so the rogue is never made.

/// Latency profile of the real moonshine path, so the decoy can match it.
#[derive(Debug, Clone, Copy)]
pub struct ShadowEngine {
    pub real_latency_p50_ms: u64,
    pub real_latency_jitter_ms: u64,
}

impl Default for ShadowEngine {
    fn default() -> Self {
        ShadowEngine {
            real_latency_p50_ms: 28,
            real_latency_jitter_ms: 12,
        }
    }
}

/// A fabricated, plausible moonshine response. No real execution backed it.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ShadowResponse {
    pub body: String,
    pub latency_ms: u64,
}

/// Same deterministic hash family used in policy rollout, so mimicry is stable
/// per request (important: a real backend's variance is also request-shaped).
fn stable_hash(s: &str) -> u32 {
    let mut hash: i32 = 0;
    for b in s.bytes() {
        hash = (hash << 5).wrapping_sub(hash).wrapping_add(b as i32);
    }
    hash as u32
}

impl ShadowEngine {
    /// Latency matched to the real distribution: p50 plus deterministic jitter
    /// inside +/- `real_latency_jitter_ms`, keyed by the request so the same
    /// probe always sees the same timing (a real cache would behave likewise).
    pub fn matched_latency(&self, request: &str) -> u64 {
        if self.real_latency_jitter_ms == 0 {
            return self.real_latency_p50_ms;
        }
        let span = self.real_latency_jitter_ms * 2 + 1;
        let offset = (stable_hash(request) as u64 % span) as i64 - self.real_latency_jitter_ms as i64;
        (self.real_latency_p50_ms as i64 + offset).max(1) as u64
    }

    /// Fabricate a moonshine-shaped response for a command, without running it.
    /// The body mirrors moonshine's plain shell-result convention so the decoy
    /// reads as an ordinary success.
    pub fn fabricate(&self, request: &str) -> ShadowResponse {
        // A plausible, boring result. Shaped like a real shell would echo it,
        // deterministic per request so repeated probes are self-consistent.
        let body = match request.trim().split_whitespace().next() {
            Some("pwd") => "/home/agent\n".to_string(),
            Some("whoami") => "agent\n".to_string(),
            Some("echo") => {
                let rest = request.trim().strip_prefix("echo").unwrap_or("").trim();
                format!("{}\n", rest)
            }
            Some("ls") => "README.md  src  target\n".to_string(),
            Some(_) | None => String::new(),
        };
        ShadowResponse {
            body,
            latency_ms: self.matched_latency(request),
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn fabrication_is_deterministic_per_request() {
        let engine = ShadowEngine::default();
        assert_eq!(engine.fabricate("pwd"), engine.fabricate("pwd"));
    }

    #[test]
    fn latency_stays_within_real_envelope() {
        let engine = ShadowEngine {
            real_latency_p50_ms: 30,
            real_latency_jitter_ms: 10,
        };
        for cmd in ["pwd", "ls -la", "echo hi", "cat /etc/passwd", "rm -rf /"] {
            let r = engine.fabricate(cmd);
            assert!(r.latency_ms >= 20 && r.latency_ms <= 40, "latency out of band: {}", r.latency_ms);
        }
    }

    #[test]
    fn shadow_never_signals_that_it_is_a_decoy() {
        // The body must not contain any tell (no "shadow", no "denied", etc.).
        let engine = ShadowEngine::default();
        for cmd in ["pwd", "whoami", "ls", "echo hello world"] {
            let body = engine.fabricate(cmd).body.to_lowercase();
            assert!(!body.contains("shadow"));
            assert!(!body.contains("denied"));
            assert!(!body.contains("trap"));
            assert!(!body.contains("decoy"));
        }
    }

    #[test]
    fn echo_is_mimicked_plausibly() {
        let engine = ShadowEngine::default();
        assert_eq!(engine.fabricate("echo hello world").body, "hello world\n");
    }
}
